import {{ Injectable }} from '@nestjs/common';
import {{ CommentService }} from './models/comment.model';
import {{ CommentServiceRepository }} from './repositories/comment.repository';

@Injectable()
export class CommentServiceService {{
  constructor(
    private readonly repository: CommentServiceRepository,
  ) {{}}

  async findAll(): Promise<CommentService[]> {{
    return this.repository.findAll();
  }}

  async findById(id: string): Promise<CommentService | null> {{
    return this.repository.findById(id);
  }}

  async create(data: Partial<CommentService>): Promise<CommentService> {{
    return this.repository.create(data);
  }}

  async update(id: string, data: Partial<CommentService>): Promise<CommentService> {{
    return this.repository.update(id, data);
  }}
}}
